#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=3e2+5;
int t[MAXN][2],f[MAXN][MAXN][2],n,m,k;
vector<PII> g[MAXN];
void dfs(int u,int fa)
{
	f[u][0][0]=f[u][1][1]=0;
	FOI(s,g[u])
	{
		if(s.fst==fa)continue;
		dfs(s.fst,u);
		FOR(i,0,n)
		{
			FOR(j,0,1)
			{
				t[i][j]=f[u][i][j];
				f[u][i][j]=inf;
			}
		}
		FOR(i,0,k)
		{
			FOR(j,0,i)
			{
				f[u][i][0]=min(f[u][i][0],min(f[s.fst][j][0]+t[i-j][0]+(m==2)*s.snd,f[s.fst][j][1]+t[i-j][0]));
				f[u][i][1]=min(f[u][i][1],min(f[s.fst][j][1]+t[i-j][1]+s.snd,f[s.fst][j][0]+t[i-j][1]));
			}
		}
	}
}
signed main(void)
{
	memset(f,0x3f,sizeof f); 
	IOS
	cin>>n>>m>>k;
    FOR(i,1,n-1)
    {
		int u,v,w;
		cin>>u>>v>>w;
		g[u].pb(mk(v,w));
		g[v].pb(mk(u,w));
	}
	if(n-k<m-1)
	{
		cout<<"-1";
		return false;
	}
	dfs(1,-1);
	cout<<f[1][k][1];
    return false;
}
